		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'pfms_num' => Request::val('pfms_num', ''),
		'date' => Request::dateComponents('date', '1'),
		'description' => br2nl(Request::val('description', '')),
		'amount' => Request::val('amount', ''),
		'requested_by' => Request::val('requested_by', ''),
		'paid_to' => Request::val('paid_to', ''),
		'paid_status' => Request::val('paid_status', ''),
		'payment_date' => Request::dateComponents('payment_date', '1'),
		'remarks' => Request::val('remarks', ''),
		'upload_scanned_file_1' => Request::fileUpload('upload_scanned_file_1', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('payment_track_details_table', 'upload_scanned_file_1', 'tv'));
				Thumbnail::create($name, getThumbnailSpecs('payment_track_details_table', 'upload_scanned_file_1', 'dv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('payment_track_details_table', 'upload_scanned_file_1', Request::val('SelectedID'));
			},
		]),
		'upload_scanned_file_2' => Request::fileUpload('upload_scanned_file_2', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
