				Thumbnail::create($name, getThumbnailSpecs('payment_track_details_table', 'upload_scanned_file_2', 'tv'));
				Thumbnail::create($name, getThumbnailSpecs('payment_track_details_table', 'upload_scanned_file_2', 'dv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('payment_track_details_table', 'upload_scanned_file_2', Request::val('SelectedID'));
			},
		]),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('payment_track_details_table', $data, $recordOwner, $error_message);

