function payment_track_details_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('payment_track_details_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: payment_track_details_table_before_delete
	if(function_exists('payment_track_details_table_before_delete')) {
		$args = [];
		if(!payment_track_details_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `payment_track_details_table` WHERE `payment_track_details_id`='{$selected_id}'", $eo);

	// hook: payment_track_details_table_after_delete
	if(function_exists('payment_track_details_table_after_delete')) {
		$args = [];
		payment_track_details_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='payment_track_details_table' AND `pkValue`='{$selected_id}'", $eo);
}

