		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('payment_track_details_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: payment_track_details_table_before_update
	if(function_exists('payment_track_details_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!payment_track_details_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'payment_track_details_table',
		backtick_keys_once($set),
		['`payment_track_details_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="payment_track_details_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('payment_track_details_table', $data['selectedID'], calculated_fields()['payment_track_details_table']);

	// hook: payment_track_details_table_after_update
	if(function_exists('payment_track_details_table_after_update')) {
		if($row = getRecord('payment_track_details_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['payment_track_details_id'];
		$args = ['old_data' => $old_data];
		if(!payment_track_details_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('payment_track_details_table', $selected_id);
}

